printf("a[%d,%d]=%-4d",row,col,*(*(p+row)+col));
printf("\n");
/*
通过改变指针p
修改数组a
的行地址，改变col
的值修改数组a
的列地址*/
for(p=a,row=0;p<a+3;p++,row++)
